import Page from 'components/Page';
import React from 'react';
import Searchable from 'react-select';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { findPerfByStream, findTerms, findAssessments, findFormStreams, findStreamMarkList, findStreamMarkReports,} from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
class PerfSearchByStreamPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          stream : 'nn',
          term : 'nn',
          group : 'nn',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          terms: [],
          streams: [],
          groups: [],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findTerms(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    terms:response.data,
                });
            }).catch((respError) => {});
            findFormStreams(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    streams:response.data,
                });
            }).catch((respError) => {});
            findAssessments(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    groups:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }
    
    handleStreamInput = (event) => {
        const v = event.target.value;
        this.setState({ ...this.state, stream: v,});
    }
    handleTermInput = (event) => {
        const v = event.target.value;
        this.setState({ ...this.state, term: v,});
    }
    handleGroupInput = (event) => {
        const v = event.target.value;
        this.setState({ ...this.state, group: v,});
    }
    handleSearchPerformanceChanges = () => {
        this.setState({
          ...this.state,
          preload:true,
        });
        findPerfByStream(this.state.xtoken, this.state)
        .then((response) => {
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    handleDownloadMarkList = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        findStreamMarkList(this.state.xtoken, this.state)
        .then((response) => {
            if( response.status === 200)
            {
                const url = response.fileurl;
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', 'statement');
                link.setAttribute('target', '_blank');
                link.click();
                this.setState({
                    ...this.state,
                    preload:false,
                    fileurl: response.fileurl,
                    error: '',
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    handleDownloadRunReports = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        findStreamMarkReports(this.state.xtoken, this.state)
        .then((response) => {
            if( response.status === 200)
            {
                const url = response.fileurl;
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', 'statement');
                link.setAttribute('target', '_blank');
                link.click();
                this.setState({
                    ...this.state,
                    preload:false,
                    fileurl: response.fileurl,
                    error: '',
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
                name: 'Id',
                options: {
                display: false
                }
            },
            'Term/Year',
            {
                name: 'Admission',
                options: {
                  display: false
                }
            },
            'Student',
            'Form',
            'Stream',
            'Subject',
            'Assessment',
            'Score',
            'Grade',
            'Remarks',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.ylabel,
                item.admlabel,
                item.slabel,
                item.flabel,
                item.streamlabel,
                item.sublabel,
                item.alabel,
                item.mark,
                item.grade,
                item.remark,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: false,
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 40,
            selectToolbarPlacement: 'replace',
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Performance - Stream reports" breadcrumbs={[{ name: 'Stream reports', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>{this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleEmail">Stream*</Label>
                      <Input onChange={this.handleStreamInput} value={this.state.stream} defaultValue={this.state.stream} type="select" name="frm">
                        <option value="nn" disabled={true}>Select stream</option>
                        {this.state.streams.map((stt, idx) => (
                            <option value={stt.id}>{stt.form + ' ' + stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>     
                  <FormGroup>
                      <Label for="exampleEmail">Term*</Label>
                      <Input onChange={this.handleTermInput} value={this.state.term} defaultValue={this.state.term} type="select" name="frm">
                        <option value="nn" disabled={true}>Select term</option>
                        {this.state.terms.map((stt, idx) => (
                            <option value={stt.id}>{stt.year + ' ' + stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>     
                  <FormGroup>
                      <Label for="exampleEmail">Assessment*</Label>
                      <Input onChange={this.handleGroupInput} value={this.state.group} defaultValue={this.state.group} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Assessment</option>
                        {this.state.groups.map((stt, idx) => (
                            <option value={stt.id}>{stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                    <Form>
                        <FormGroup>
                            <Button className="btn-custom" type="button" onClick={this.handleSearchPerformanceChanges}>View Records</Button>
                            <Button className="btn-custom" type="button" color="warning" onClick={this.handleDownloadMarkList}>Download Mark list</Button>
                            <Button className="btn-custom" type="button" color="danger" onClick={this.handleDownloadRunReports}>Run Term Reports</Button>
                        </FormGroup>
                    </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'Stream reports'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.ylabel,
                        item.admlabel,
                        item.slabel,
                        item.flabel,
                        item.streamlabel,
                        item.sublabel,
                        item.alabel,
                        item.mark,
                        item.grade,
                        item.remark,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default PerfSearchByStreamPage;
